                write(f"[*] Updated '{field}' for '{profile_name}' to '{value}'.")

            cls.addProfile(profile_data) # This will save the updated profile
        except Exception:
            error(traceback.format_exc())
            write(f"[-] Failed to edit profile '{profile_name}'.")

